import json
import networkx as nx
import matplotlib.pyplot as plt
from pyvis.network import Network

# Load deps.json generated by:
# flutter pub deps --json > deps.json
with open("deps.json", "r") as f:
    data = json.load(f)

# # Initialize graph
# G = nx.DiGraph()

internal_packages = ["chef",     "launcher" ,"io","ui"     ,"event"     ,"gluttex_core","impl_app","impl_mediation","login","gluttex_play","gluttex_constants","gluttex_home","business","store_geo"  ,"health","locator","product_catalog"]

ui_packages = ["chef",     "launcher","ui","login","gluttex_play","product_catalog","gluttex_home","health","store_geo"]

# Define what counts as "internal"
def is_internal(pkg):
    return pkg in internal_packages

# Create directed graph
G = nx.DiGraph()

# # Add nodes and edges (excluding third-party)
# our_packages = {pkg["name"] for pkg in data["packages"]}

for pkg in data["packages"]:
    pkg_name = pkg["name"]
    for dep in pkg.get("dependencies", []):
        # if is_internal(dep):  # only include in-house deps
        G.add_node(pkg_name)
        if is_internal(pkg_name):
            G.add_edge(pkg_name,dep)


# PyVis graph
net = Network(height="100vh",
    width="100vw",
 directed=True, notebook=False)
net.barnes_hut()

# Compute in-degree (number of incoming edges)
in_degrees = dict(G.in_degree())



# Add nodes with size proportional to in-degree
for node in G.nodes():
    size = 15 + in_degrees.get(node, 0) * 8  # base size + scaled by in-degree
    # color = "#ff6666" if node == data["root"] else "#66b3ff"
    
    if(node in ui_packages):
        color = "#33ff00"
    else:
        if node in internal_packages:
            color = "#66b3ff"
        else:
            color = "#ff6666"
    if node == data["root"]:
        color = "#ffae00"

    net.add_node(node, size=size, color=color,gravity=-90000, image="package.svg", title=f"{node} dependencies: {len(list(G.successors(node)))}")

# Add edges
for source, target in G.edges():
    net.add_edge(source, target)

net.set_options("""
{
  "nodes": {
    "font": {
      "size": 16,
      "strokeWidth": 0.5
    }
  }
}
""")

# Save to HTML
net.write_html("dependencies.html")